// roundHalfEven(x): round x to the nearest integer using round-half-to-even
// (banker's rounding) per SPEC.md. Exact halves go to the nearest EVEN
// integer; all other values round normally.
function roundHalfEven(x) {
  const f = Math.floor(x);
  const diff = x - f;
  if (diff < 0.5) return f;
  if (diff > 0.5) return f + 1;
  // Exactly halfway: round to the nearest even integer.
  return f % 2 === 0 ? f : f + 1;
}
module.exports = { roundHalfEven };
